import{getItemCount as a,subscribe as e}from"../utils/cart-store.js";export function renderHeader(t){t.innerHTML='\n    <a class="brand" href="/">Power<span>Ledger</span></a>\n    <nav aria-label="Primary">\n      <a href="/">Catalog</a>\n      <a href="/cart" class="cart-link">\n        Cart <span class="cart-badge" id="cart-badge" aria-hidden="true">0</span>\n        <span class="visually-hidden" id="cart-badge-text">, 0 items</span>\n      </a>\n    </nav>\n  ';const n=t.querySelector("#cart-badge"),r=t.querySelector("#cart-badge-text");function s(){const e=a();n.textContent=String(e),r.textContent=", "+e+(1===e?" item":" items")}s(),e(s)}